#include <bits/stdc++.h>
using namespace std;

int uniquePaths(int n, int m, int x, int y) {
   // Create a grid with the Native American as obstacle
   vector<vector<int>> grid(n, vector<int>(m, 0));
   grid[x-1][y-1] = 1; // Mark Native American position as obstacle (converting to 0-based indexing)

   // Initialize dp array
   vector<int> dp(m, 0);
   dp[0] = 1;

   // If Native American is at start or end, return 0
   if (grid[0][0] == 1 || grid[n-1][m-1] == 1) {
       return 0;
   }

   for (int r = 0; r < n; r++) {
       for (int c = 0; c < m; c++) {
           if (grid[r][c] == 1) {
               dp[c] = 0;
           } else {
               if (c > 0) {
                   dp[c] += dp[c-1];
               }
           }
       }
   }

   return dp[m-1];
}

int main() {
   int t;
   cin >> t;

   while(t--) {
       int n, m, x, y;
       cin >> n >> m >> x >> y;
       cout << uniquePaths(n, m, x, y) << "\n";
   }

   return 0;
}

